const channel = (msg.payload.channel || 'all').toLowerCase();
const title = msg.payload.title || 'Alert';
const message = msg.payload.message || '';
const severity = (msg.payload.severity || 'warning').toUpperCase();

const colors = { INFO: 2122957, WARNING: 16761856, CRITICAL: 16711680 };
const color = colors[severity] || colors.WARNING;

const feishuCard = {
    msg_type: 'interactive',
    card: {
        header: { title: { tag: 'plain_text', content: title }, template: severity === 'CRITICAL' ? 'red' : severity === 'WARNING' ? 'yellow' : 'blue' },
        elements: [{ tag: 'markdown', content: message }]
    }
};

const wecomMsg = {
    msgtype: 'markdown',
    markdown: { content: `## ${title}\n${message}` }
};

msg.payload = { channel, feishuCard, wecomMsg, title, message, severity };
return msg;
